SET SERVEROUTPUT ON SIZE UNLIMITED
SET DEFINE OFF
DECLARE
    TYPE t_arr IS TABLE OF VARCHAR2(10) INDEX BY PLS_INTEGER;
    v_tk_admin VARCHAR2(10); v_tk_bdh t_arr; v_tk_tnv t_arr;
    v_dt_ids t_arr; v_loai_ids t_arr; v_cd_ids t_arr;
    v_cv_ids t_arr; v_tg_ids t_arr; v_pc_ids t_arr;
    v_tmp VARCHAR2(10); v_tmp2 VARCHAR2(10);
    v_tn_ids t_arr; v_ma_phieu VARCHAR2(10);
BEGIN
    -- 0A. DISABLE TẤT CA TRIGGERS TRUOC KHI XOA
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_CHANXOA_CHIENDICH DISABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_THOIGIAN DISABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_TRUNG_LICH DISABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_SOLUONG_DANGKY DISABLE';
    DELETE FROM ThongBao;
    DELETE FROM TheoDoi;
    DELETE FROM BinhLuan;
    DELETE FROM GiayChungNhan;
    DELETE FROM DiemDanh;
    DELETE FROM PhanCong;
    DELETE FROM ThamGiaTNV;
    DELETE FROM ThanhToan;
    DELETE FROM QuyenGopTien;
    DELETE FROM TaiTro;
    DELETE FROM ChiTieu;
    DELETE FROM MinhChungChiTieu;
    DELETE FROM ChiTietXuatVP;
    DELETE FROM PhieuXuatVatPham;
    DELETE FROM ChiTietQuyenGopVP;
    DELETE FROM PhieuQuyenGopVP;
    DELETE FROM KhoChienDich;
    DELETE FROM CongViec;
    DELETE FROM TinTuc;
    DELETE FROM DuyetChienDich;
    DELETE FROM BanDieuHanh;
    DELETE FROM ChienDich;
    DELETE FROM HoSoSinhVien;
    DELETE FROM NhatKyHeThong;
    DELETE FROM TaiKhoan;
    DELETE FROM DoiTac;
    DELETE FROM LoaiVatPham;
    DELETE FROM ThamSo;
    DBMS_OUTPUT.PUT_LINE('>> Cleanup: OK');
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(1));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(2));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(3));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(4));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(5));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(6));
    SP_CAP_CHUNGNHAN_CD(v_cd_ids(7));
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 950 WHERE MaChienDich=v_cd_ids(7) AND MaLoai=v_loai_ids(6);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 480 WHERE MaChienDich=v_cd_ids(7) AND MaLoai=v_loai_ids(7);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 190 WHERE MaChienDich=v_cd_ids(7) AND MaLoai=v_loai_ids(8);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 300 WHERE MaChienDich=v_cd_ids(4) AND MaLoai=v_loai_ids(9);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 50 WHERE MaChienDich=v_cd_ids(4) AND MaLoai=v_loai_ids(10);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 195 WHERE MaChienDich=v_cd_ids(6) AND MaLoai=v_loai_ids(11);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 390 WHERE MaChienDich=v_cd_ids(6) AND MaLoai=v_loai_ids(12);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 480 WHERE MaChienDich=v_cd_ids(6) AND MaLoai=v_loai_ids(5);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 90 WHERE MaChienDich=v_cd_ids(1) AND MaLoai=v_loai_ids(1);
    UPDATE KhoChienDich SET SoLuongTon = SoLuongTon - 95 WHERE MaChienDich=v_cd_ids(1) AND MaLoai=v_loai_ids(2);
    UPDATE HoSoSinhVien hs
    SET TongDiem = NVL(
        (SELECT SUM(tg.DiemDanhGia) + SUM(cd.DiemThuong)
         FROM ThamGiaTNV tg
         JOIN ChienDich cd ON tg.MaChienDich = cd.MaChienDich
         WHERE tg.MaTaiKhoan = hs.MaTaiKhoan AND tg.TrangThaiDuyet = 'HoanThanh'), 0);
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_CHANXOA_CHIENDICH ENABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_THOIGIAN ENABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_TRUNG_LICH ENABLE';
    EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_SOLUONG_DANGKY ENABLE';
    COMMIT;
    DBMS_OUTPUT.PUT_LINE('>> SEED DATA DEMO HOAN THANH THANH CONG!');
EXCEPTION
    WHEN OTHERS THEN
        EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_CHANXOA_CHIENDICH ENABLE';
        EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_THOIGIAN ENABLE';
        EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_TRUNG_LICH ENABLE';
        EXECUTE IMMEDIATE 'ALTER TRIGGER TRG_KIEMTRA_SOLUONG_DANGKY ENABLE';
        ROLLBACK;
        DBMS_OUTPUT.PUT_LINE('>> LOI: ' || SQLERRM);
        RAISE;
END;
/